'CreateAgentRuntimeRequest$protocolConfiguration' => NULL, 'GetAgentRuntimeResponse$protocolConfiguration' => NULL, 'UpdateAgentRuntimeRequest$protocolConfiguration' => NULL, ], ], 'PutResourcePolicyRequest' => [ 'base' => NULL, 'refs' => [], ], 'PutResourcePolicyResponse' => [ 'base' => NULL, 'refs' => [], ], 'RatingScale' => [ 'base' => '<p> The rating scale that defines how evaluators should score agent performance, supporting both numerical and categorical scales. </p>', 'refs' => [ 'LlmAsAJudgeEvaluatorConfig$ratingScale' => '<p> The rating scale that defines how the evaluator should score agent performance, either numerical or categorical. </p>', ], ], 'RecordIdentifier' => [ 'base' => NULL, 'refs' => [ 'DeleteRegistryRecordRequest$recordId' => '<p>The identifier of the registry record to delete. You can specify either the Amazon Resource Name (ARN) or the ID of the record.</p>', 'GetRegistryRecordRequest$recordId' => '<p>The identifier of the registry record to retrieve. You can specify either the Amazon Resource Name (ARN) or the ID of the record.</p>', 'SubmitRegistryRecordForApprovalRequest$recordId' => '<p>The identifier of the registry record to submit for approval. You can specify either the Amazon Resource Name (ARN) or the ID of the record.</p>', 'UpdateRegistryRecordRequest$recordId' => '<p>The identifier of the registry record to update. You can specify either the Amazon Resource Name (ARN) or the ID of the record.</p>', 'UpdateRegistryRecordStatusRequest$recordId' => '<p>The identifier of the registry record to update the status for. You can specify either the Amazon Resource Name (ARN) or the ID of the record.</p>', ], ], 'RecordingConfig' => [ 'base' => '<p>The recording configuration for a browser. This structure defines how browser sessions are recorded.</p>', 'refs' => [ 'CreateBrowserRequest$recording' => '<p>The recording configuration for the browser. When enabled, browser sessions are recorded and stored in the specified Amazon S3 location